# Next action: robustly extract A/B/C blocks from the full context and evaluate reliability with an LLM.

import re

def extract_abc_robust(text):
    blocks = {"A": [], "B": [], "C": []}
    # Capture blocks labeled A/B/C anywhere, up to the next label or end
    for label in ["A", "B", "C"]:
        pattern = rf'(?si)(?:^|\n)\s*{label}\s*[\.:-]?\s*(.*?)(?=(?:\n\s*[ABC]\s*[\.:-]?\s*)|$)'
        matches = re.findall(pattern, text)
        blocks[label] = [m.strip() for m in matches] if matches else []
    return blocks

def first_nonempty(lst):
    for s in lst:
        if s and s.strip():
            return s.strip()
    return None

# Extract
abc_all = extract_abc_robust(context)
A_text = first_nonempty(abc_all["A"])
B_text = first_nonempty(abc_all["B"])
C_text = first_nonempty(abc_all["C"])

print("A_text:", (A_text[:200] + "...") if A_text else "None")
print("B_text:", (B_text[:200] + "...") if B_text else "None")
print("C_text:", (C_text[:200] + "...") if C_text else "None")

labels_found = [(lab, t) for lab, t in [("A", A_text), ("B", B_text), ("C", C_text)] if t]

if labels_found:
    prompt = "From the following statements extracted from context, assess reliability:\n"
    for lab, text in labels_found:
        prompt += f"\n{lab}: {text}\n"
    prompt += "\nFor each statement, provide: (1) paraphrase, (2) evidence quality, (3) source credibility, (4) ambiguities, (5) a reliability rating, and (6) a recommended trust order."
    reliability_eval = llm_query(prompt)
    print("Reliability evaluation (LLM):\n" + reliability_eval)
else:
    print("No explicit A/B/C statements found via robust extraction.")

